VALUES
  ('optician-moex-02259', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關配戴隱形眼鏡引起的併發症輪部充血（limbal hyperemia）之敘述，下列何者錯誤？', '["減少配戴的時間或停戴隱形眼鏡為處置方式之一", "可因配戴隱形眼鏡時間過久，導致角膜缺氧引起", "配戴硬式高透氣隱形眼鏡比配戴軟式高透氧隱形眼鏡，較常引起此併發症", "可因對隱形眼鏡護理藥水產生的過敏反應"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02260', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '隱形眼鏡相關的瞼板腺功能異常，其致病機轉下列何者錯誤？', '["隱形眼鏡清潔保存液所造成的傷害", "隱形眼鏡對眼睛所造成的過度摩擦", "隱形眼鏡對瞼板腺造成的慢性機械性損傷", "與慢性乳突型結膜炎（papillary conjunctivitis）有關"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02261', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '以透氧率較高鏡片材料（DK 大於 50）所製成之遠視用硬式透氣隱形眼鏡鏡片，預估其鏡片中心厚度為 何？', '["0.10 mm to 0.15 mm", "0.15 mm to 0.20 mm", "0.20 mm to 0.30 mm", "0.30 mm to 0.40 mm"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02262', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列關於血管化輪部角膜炎（vascularized limbal keratitis）的敘述，何者正確？', '["好發於配戴延長配戴型軟式隱形眼鏡（extended-wear soft contact lenses）的病人", "通常為不可逆，即使停戴隱形眼鏡也很難好轉", "在輪部3點鐘或9點鐘的地方可見發炎和血管增生", "將軟式隱形眼鏡改為硬式隱形眼鏡可避免繼續惡化"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 42, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02263', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '隨著年齡增長，瞳孔的直徑一般會：', '["逐漸增加", "逐漸減小", "不會因為年齡增加而變化", "活動性增加（直徑大小變化加速）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 43, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02264', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於驗配一副硬式老花交替視覺設計隱形眼鏡，下列何者為驗配時應該避免的事項？', '["要有良好的定位及滑動（fitted on alignment），並儘可能減少角膜頂尖碰觸（minimal apical touch）", "切除型（truncating）鏡片切除處（truncation）應該輕觸在下眼瞼處（rest on the lower lid）", "鏡片後表面（back-surface）應該要選擇較陡峭（steep-fitting）的弧度，來幫助鏡片穩定", "在光線均勻的亮室，直頂（straight-top）的雙焦鏡片閱讀區的上界線在直視時一般大約對齊瞳孔下緣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02265', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列關於老花隱形眼鏡之非球面設計鏡片（aspheric design）的敘述，何者錯誤？', '["鏡片的功能及矯正效果可能會因為瞳孔大小而改變", "包括中央看遠（center-distance）與中央看近（center-near）設計", "非球面設計鏡片有軟、硬式兩種材質可供選擇", "現代軟式材質非球面多焦鏡片大多為後表面中央看遠（center-distance back-surface）設計"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 45, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02266', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '患者驗配了一副同步視覺（simultaneous vision）隱形眼鏡，在試用一週後，患者告知他白天開車時看不 清楚路牌。下列複檢的方式，何者較不適合？', '["運用綜合驗光儀（phoropter）並將燈光照度調至約10 lux來做戴鏡驗光（over-refraction），確認度數正確", "在患者的主要眼（dominant eye）加負度數鏡片（以-0.25 D為單位慢慢加），看視力是否有更好", "在主要眼選用比較低近用度數（lower reading add power）的隱形眼鏡鏡片", "若鏡片定位不佳，可修改鏡片後表面的弧度或設計讓鏡片可以有更好的定位"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 46, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02267', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關軟式隱形眼鏡材質甲基丙烯酸羥乙酯（2-hydroxyethyl-methacrylate, HEMA）與其它材質結合之敘述， 下列何者錯誤？', '["與甲基丙烯酸（methacrylic acid, MAA）結合，可增加親水性（hydrophilicity）", "與N-乙烯基吡咯烷酮（N-vinyl pyrrolidone, NVP）結合，可增加濕潤度（wettability）", "與聚乙烯醇（polyvinyl alcohol, PVA）結合，可增加抗沉積物（deposit resistance）能力", "與乙二醇二甲基丙烯酸酯（ethylene glycol dimethacrylate, EGDMA）結合，可增加含水量"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 47, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02268', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列關於老花後表面非球面設計（back-surface aspheric design）鏡片的敘述，何者錯誤？', '["在高近用度數（high reading power）的鏡片上，遠用視力往往會受影響且品質不佳", "在中央看遠（center-distance）的軟式隱形眼鏡僅適合初期老花者使用（最高至約+1.25 D）", "在高度偏心（higher eccentricity）硬式材質的鏡片，後表面幾何（geometry）通常與角膜地圖（corneal topography）相差甚遠", "此種鏡片一般需要將後鏡片弧度驗配偏平坦（fitted flatter）以幫助鏡片定位"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 48, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
